const router=require('express').Router(),db=require('../database/db'),{authenticate}=require('../middleware/auth');
router.get('/',authenticate,async(req,res)=>{const{companyId}=req.query;const[r]=await db.query('SELECT * FROM rules WHERE company_id=? ORDER BY priority,id',[companyId]);res.json(r);});
router.post('/',authenticate,async(req,res)=>{const{companyId,name,type,condition,action,priority,isEnabled}=req.body;const[r]=await db.query('INSERT INTO rules(company_id,name,type,condition_json,action_json,priority,is_enabled)VALUES(?,?,?,?,?,?,?)',[companyId,name,type,JSON.stringify(condition),JSON.stringify(action),priority||1,isEnabled?1:0]);const[rows]=await db.query('SELECT * FROM rules WHERE id=?',[r.insertId]);res.json(rows[0]);});
router.put('/:id',authenticate,async(req,res)=>{const{name,type,condition,action,priority,isEnabled}=req.body;await db.query('UPDATE rules SET name=?,type=?,condition_json=?,action_json=?,priority=?,is_enabled=? WHERE id=?',[name,type,JSON.stringify(condition),JSON.stringify(action),priority,isEnabled?1:0,req.params.id]);const[r]=await db.query('SELECT * FROM rules WHERE id=?',[req.params.id]);res.json(r[0]);});
router.delete('/:id',authenticate,async(req,res)=>{await db.query('DELETE FROM rules WHERE id=?',[req.params.id]);res.json({message:'Deleted'});});
router.get('/logs',authenticate,async(req,res)=>{const{companyId}=req.query;const[r]=await db.query('SELECT * FROM rule_logs WHERE company_id=? ORDER BY triggered_at DESC LIMIT 200',[companyId]);res.json(r);});
router.post('/logs',authenticate,async(req,res)=>{const{companyId,ruleId,triggerContext,result}=req.body;await db.query('INSERT INTO rule_logs(company_id,rule_id,trigger_context,result)VALUES(?,?,?,?)',[companyId,ruleId,JSON.stringify(triggerContext),JSON.stringify(result)]);res.json({message:'Logged'});});
module.exports=router;
